import axios from "axios";

export const updatePeriod = async ({ year, section, day, period, updates }) => {
  try {
    const res = await axios.put("/api/timetable/update", {
      year, section, day, period, updates
    });
    return res.data;
  } catch (err) {
    console.error("Update failed:", err.response?.data || err.message);
    throw err;
  }
};
